这段代码最后调用ontimer也是这个道理吗：void CBL420NFactorySettingToolSensorView::OnTimer(UINT_PTR nIDEvent)
{
	// TODO: 在此添加消息处理程序代码和/或调用默认值，
	if ( nIDEvent == ID_DEVCHECK_TIMER )
	{
		/// 1.---------------------------- 查看设备是否存在 ---------------------------------------
		if ( m_pUSB->List_Devices() > 0  )
		{
			if( !m_Start_Enable )
			{
				m_Start_Enable	= true;
				m_bStart_Flag = false;
			}
		}
		else
		{
			if ( m_Start_Enable )
			{
				m_Start_Enable	= false;
				m_bStart_Flag	= true;
			}
		}
	}
	else if ( nIDEvent == ID_RUNMODEL_TIMER )
	{
		if ( m_bStart_Flag ) /// 如果已经开始了，那么我去检查一下线程是否退出
		{
			ONE_PHYSIC_SENSOR sensorInfo;
			long lRet = Get_Sensor_Info(&sensorInfo,m_pUSB,true);
			if ( lRet == SENSOR_CHANGE_ON )
			{
				m_pGrid->SetItemImage(1,SENSOR_IMAGE,1);
				if ( !m_bErease )
				{
					OnBtnSensorErase();
				}

			}
			else if ( lRet == SENSOR_CHANGE_OFF )
			{
				m_pGrid->SetItemImage(1,SENSOR_IMAGE,0);
				memset(&sensorInfo,0,sizeof(ONE_PHYSIC_SENSOR));
				SetSensorBasicInfo(&sensorInfo);
				m_pGrid->SetItemImage(1,SENSOR_STATE,-1);
			}
			Invalidate();	
		}
		else
		{
			KillTimer(ID_RUNMODEL_TIMER);
			return;
		}
	}
	else if ( nIDEvent == ID_EREASE_TIMER )
	{
		m_bErease = true;
		static int nIndex = 7;
		///UI运行模式
		if (nIndex == 2 )
		{
			nIndex = 7;
		}
		m_pGrid->SetItemImage(1,SENSOR_STATE,nIndex);
		nIndex--;
		Invalidate();
		long lRet = DoEreaseSensorInfo(false);
		if ( lRet >= 15  || lRet == ERROR_USB)
		{
			m_bErease = false;
			DoEreaseSensorInfo(true);
			m_pGrid->SetItemImage(1,SENSOR_STATE,8);
			KillTimer(ID_EREASE_TIMER);

		}

	}
	else if( ID_NOTIFY_TIMER == nIDEvent )
	{
		if ( WaitForSingleObject(m_Thread_Notify_Info_Event,0) == WAIT_OBJECT_0 )
		{
			AddStringToList(m_strNotifyInfo);
			m_Thread_Notify_Info_Event.ResetEvent();
		}
	}
	CFormView::OnTimer(nIDEvent);
}

在C++中，类的成员可以被声明为 public、protected 或 private。protected 成员是一种访问权限，它可以在类的内部和子类中访问，但不能在类的外部使用。protected 成员的特点如下：

1. protected 成员可以在当前类的成员函数中访问和修改，就像 private 成员一样。

2. protected 成员可以在子类中访问和修改，就像 public 成员一样。

3. protected 成员不能在类的外部直接访问。

使用 protected 成员有几个常见的目的和用途：

1. 继承：当一个类派生出子类时，可以使用 protected 成员来允许子类访问和修改父类的成员。这种继承关系可以使用继承方式（public、protected 或 private）来控制。

2. 封装与继承的平衡：protected 成员提供了介于 private（完全封装）和 public（完全暴露）之间的访问权限。这使得某些成员可以在子类中访问和修改，同时保持其他代码（包括子类的代码）无法访问和修改的特性。

3. 代码复用：通过在父类中将一些函数或变量定义为 protected，子类可以继承并使用这些函数或变量，从而实现代码的复用。

下面是一个示例代码，演示了 protected 成员的使用：

```cpp
class Base {
protected:
    int protectedVar;

public:
    void publicMethod() {
        // 访问 protected 成员
        protectedVar = 10;
    }
};

class Derived : public Base {
public:
    void derivedMethod() {
        // 可以访问和修改父类的 protected 成员
        protectedVar = 20;
    }
};

int main() {
    Base base;
    base.protectedVar = 5;  // 错误，protected 成员不能在类的外部直接访问

    Derived derived;
    derived.protectedVar = 15;  // 错误，protected 成员不能在类的外部直接访问

    return 0;
}
```

在上述示例中，子类 Derived 可以访问和修改父类 Base 的 protected 成员 protectedVar，但在类的外部无法直接访问。

在C++中，private 成员和 protected 成员都是用来实现类的封装性，限制对类的成员的访问。它们具有以下区别：

1. 访问权限：private 成员只能在当前类的成员函数中访问，而 protected 成员可以在当前类的成员函数和子类中访问。两者都不能在类的外部直接访问。

2. 继承：private 成员不可以被子类继承和访问，而 protected 成员可以被子类继承并在子类中访问。

3. 封装：private 成员提供了最强的封装性，封装了类的内部实现细节，更加安全。protected 成员提供了一定的封装性，但在子类中可见，以便于子类进行访问和修改。

4. 可访问性：通过将成员声明为 private 或 protected，可以控制其他代码对类成员的可见性和访问权限。private 成员对于外部代码来说完全不可见，protected 成员对于外部代码不可见但子类可见。

例子示范：

```cpp
class Base {
private:
    int privateVar;

protected:
    int protectedVar;

public:
    void publicMethod() {
        privateVar = 10;      // 访问 private 成员
        protectedVar = 20;   // 访问 protected 成员
    }
};

class Derived : public Base {
public:
    void derivedMethod() {
        privateVar = 5;       // 错误，不能访问父类的 private 成员
        protectedVar = 15;   // 正确，可以访问父类的 protected 成员
    }
};

int main() {
    Base base;
    base.privateVar = 3;       // 错误，不能直接访问私有成员
    base.protectedVar = 7;     // 错误，不能直接访问保护成员

    Derived derived;
    derived.privateVar = 8;    // 错误，不能直接访问父类的 private 成员
    derived.protectedVar = 12; // 错误，不能直接访问父类的 protected 成员

    return 0;
}
```

总的来说，private 成员提供了更高的封装性并限制了访问权限，而 protected 成员在限制访问的同时，可以在子类中允许访问和修改。根据具体需求，在设计类的时候可以选择使用适当的访问权限。

